# Configure MFA via Authentication Methods Policy (per-method enablement)
# This is the modern approach — replaces the legacy per-user MFA portal

import requests

TENANT_ID = "YOUR_TENANT_ID"

def get_token():
    r = requests.post(
        f"https://login.microsoftonline.com/{TENANT_ID}/oauth2/v2.0/token",
        data={
            "grant_type": "client_credentials",
            "client_id": "YOUR_APP_ID",
            "client_secret": "YOUR_SECRET",
            "scope": "https://graph.microsoft.com/.default",
        }
    )
    return r.json()["access_token"]

token = get_token()
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

# 1. List all authentication method configurations
resp = requests.get(
    "https://graph.microsoft.com/v1.0/policies/authenticationMethodsPolicy",
    headers=headers
)
policy = resp.json()
print(f"Policy version: {policy.get('policyVersion')}")
for method in policy.get("authenticationMethodConfigurations", []):
    print(f"  {method['@odata.type'].split('.')[-1]:<40} state={method.get('state')}")

# 2. Enable Microsoft Authenticator for all users
patch_authenticator = {
    "state": "enabled",
    "featureSettings": {
        "numberMatchingRequiredState": {
            "state": "enabled",         # required since May 2023, defeats MFA fatigue
            "includeTarget": {"targetType": "group", "id": "all_users"}
        },
        "displayAppInformationRequiredState": {
            "state": "enabled",         # shows app name + location in push notification
            "includeTarget": {"targetType": "group", "id": "all_users"}
        }
    },
    "includeTargets": [{"targetType": "group", "id": "all_users"}],
    "excludeTargets": []
}
requests.patch(
    "https://graph.microsoft.com/v1.0/policies/authenticationMethodsPolicy/authenticationMethodConfigurations/MicrosoftAuthenticator",
    headers=headers,
    json=patch_authenticator
)

# 3. Enable FIDO2 security keys
patch_fido2 = {
    "state": "enabled",
    "isSelfServiceRegistrationAllowed": True,
    "isAttestationEnforced": False,    # True = only allow FIDO2 keys from approved AAGUIDs
    "includeTargets": [{"targetType": "group", "id": "all_users"}],
    "keyRestrictions": {
        "isEnforced": False,           # Set True to restrict to specific vendors
        "enforcementType": "allow",
        "aaGuids": []
    }
}
requests.patch(
    "https://graph.microsoft.com/v1.0/policies/authenticationMethodsPolicy/authenticationMethodConfigurations/Fido2",
    headers=headers,
    json=patch_fido2
)
print("MFA methods configured.")

# Create a Conditional Access policy requiring MFA for all users
# This is the recommended way to enforce MFA — not per-user MFA settings

import requests

token = get_token()
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

# Option A: Require MFA (any method) for all cloud apps
ca_mfa_all = {
    "displayName": "Require MFA — All Users All Apps",
    "state": "enabledForReportingButNotEnforced",   # audit first
    "conditions": {
        "users": {
            "includeUsers": ["All"],
            "excludeGroups": ["BREAK-GLASS-GROUP-ID"],
            "excludeRoles": []
        },
        "applications": {
            "includeApplications": ["All"]
        },
        "platforms": None,          # all platforms
        "locations": None           # all locations
    },
    "grantControls": {
        "operator": "OR",
        "builtInControls": ["mfa"]   # any MFA method
    },
    "sessionControls": None
}

resp = requests.post(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
    headers=headers,
    json=ca_mfa_all
)
policy_id = resp.json().get("id")
print(f"CA policy created: {policy_id}")

# Option B: Require PHISHING-RESISTANT MFA for privileged roles
# Uses an Authentication Strength object
# First, retrieve the built-in phishing-resistant strength ID
strengths_resp = requests.get(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/authenticationStrength/policies",
    headers=headers
)
phishing_resistant = next(
    (s for s in strengths_resp.json().get("value", [])
     if s.get("displayName") == "Phishing-resistant MFA"),
    None
)

if phishing_resistant:
    ca_phishing_resistant = {
        "displayName": "Require Phishing-Resistant MFA — Privileged Roles",
        "state": "enabled",
        "conditions": {
            "users": {
                "includeRoles": [
                    "62e90394-69f5-4237-9190-012177145e10",  # Global Administrator
                    "194ae4cb-b126-40b2-bd5b-6091b380977d",  # Security Administrator
                    "f28a1f50-f6e7-4571-818b-6a12f2af6b6c",  # SharePoint Administrator
                    "729827e3-9c14-49f7-bb1b-9608f156bbb8",  # Helpdesk Administrator
                ],
                "excludeGroups": ["BREAK-GLASS-GROUP-ID"]
            },
            "applications": {"includeApplications": ["All"]}
        },
        "grantControls": {
            "operator": "OR",
            "authenticationStrength": {"id": phishing_resistant["id"]}
        }
    }
    requests.post(
        "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
        headers=headers,
        json=ca_phishing_resistant
    )
    print("Phishing-resistant MFA policy created for privileged roles.")

# Registration campaign: nudge users to register MFA methods
# Entra ID can interrupt sign-in to prompt unregistered users

import requests

token = get_token()
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

# Configure the registration campaign
campaign = {
    "state": "enabled",
    "snoozeDurationInDays": 3,       # users can snooze for 3 days
    "includeTargets": [
        {
            "targetType": "group",
            "id": "all_users",       # 'all_users' is a special literal
            "targetedAuthenticationMethod": "microsoftAuthenticator"
        }
    ],
    "excludeTargets": []
}

requests.patch(
    "https://graph.microsoft.com/v1.0/policies/authenticationMethodsPolicy",
    headers=headers,
    json={"registrationEnforcement": {"authenticationMethodsRegistrationCampaign": campaign}}
)
print("Registration campaign enabled — users without Authenticator will be prompted at next sign-in.")

# Check registration status for the tenant
reg_resp = requests.get(
    "https://graph.microsoft.com/v1.0/reports/authenticationMethods/userRegistrationDetails"
    "?$select=userPrincipalName,isMfaRegistered,isMfaCapable,methodsRegistered"
    "&$top=100",
    headers=headers
)
registered = 0; unregistered = 0
for user in reg_resp.json().get("value", []):
    if user.get("isMfaRegistered"):
        registered += 1
    else:
        unregistered += 1
        if unregistered <= 10:
            print(f"  Not registered: {user['userPrincipalName']}")

print(f"\nRegistered: {registered}  Not registered: {unregistered}")

# PowerShell: Audit users excluded from MFA Conditional Access policies
# Exclusions (break-glass, service accounts) should be inventoried and reviewed

Connect-MgGraph -Scopes "Policy.Read.All", "User.Read.All"

# Get all CA policies that require MFA
$policies = Get-MgIdentityConditionalAccessPolicy -All |
    Where-Object { $_.GrantControls.BuiltInControls -contains "mfa" -or
                   $_.GrantControls.AuthenticationStrength -ne $null }

foreach ($pol in $policies) {
    Write-Output "Policy: $($pol.DisplayName) [state=$($pol.State)]"

    $excUsers  = $pol.Conditions.Users.ExcludeUsers
    $excGroups = $pol.Conditions.Users.ExcludeGroups
    $excRoles  = $pol.Conditions.Users.ExcludeRoles

    if ($excUsers) {
        Write-Output "  Excluded users ($($excUsers.Count)):"
        foreach ($uid in $excUsers) {
            $u = Get-MgUser -UserId $uid -ErrorAction SilentlyContinue
            Write-Output "    $($u.UserPrincipalName ?? $uid)"
        }
    }
    if ($excGroups) {
        Write-Output "  Excluded groups ($($excGroups.Count)):"
        foreach ($gid in $excGroups) {
            $g = Get-MgGroup -GroupId $gid -ErrorAction SilentlyContinue
            Write-Output "    $($g.DisplayName ?? $gid)"
        }
    }
    Write-Output ""
}

# Register a FIDO2 security key programmatically via Graph (admin-on-behalf-of)
# Most users register interactively at aka.ms/mysecurityinfo
# Admins can view and delete registrations via Graph

import requests

def get_user_fido2_keys(token, upn):
    headers = {"Authorization": f"Bearer {token}"}
    resp = requests.get(
        f"https://graph.microsoft.com/v1.0/users/{upn}/authentication/fido2Methods",
        headers=headers
    )
    keys = resp.json().get("value", [])
    print(f"FIDO2 keys for {upn} ({len(keys)}):")
    for k in keys:
        print(f"  id={k['id'][:12]}... model={k.get('model','?')} created={k.get('createdDateTime','?')[:10]}")
        print(f"    aaGuid={k.get('aaGuid')} attestationLevel={k.get('attestationLevel')}")
    return keys

def delete_fido2_key(token, upn, key_id):
    headers = {"Authorization": f"Bearer {token}"}
    resp = requests.delete(
        f"https://graph.microsoft.com/v1.0/users/{upn}/authentication/fido2Methods/{key_id}",
        headers=headers
    )
    print(f"Deleted key {key_id[:12]}: {resp.status_code}")

# Audit: find users with no FIDO2 keys (not yet phishing-resistant)
def find_non_phishing_resistant_users(token, user_ids):
    headers = {"Authorization": f"Bearer {token}"}
    no_fido2 = []
    for uid in user_ids:
        resp = requests.get(
            f"https://graph.microsoft.com/v1.0/users/{uid}/authentication/fido2Methods",
            headers=headers
        )
        if not resp.json().get("value"):
            no_fido2.append(uid)
    return no_fido2

token = get_token()
keys = get_user_fido2_keys(token, "alice@contoso.com")

# Configure MFA session lifetime and persistent browser session
# Controls how often users are re-prompted for MFA

import requests

token = get_token()
headers = {"Authorization": f"Bearer {token}", "Content-Type": "application/json"}

# Approach 1: Sign-in frequency — re-prompt MFA after N hours
ca_signin_freq = {
    "displayName": "MFA Sign-in Frequency — 24h",
    "state": "enabled",
    "conditions": {
        "users": {"includeUsers": ["All"]},
        "applications": {"includeApplications": ["All"]}
    },
    "grantControls": {
        "operator": "OR",
        "builtInControls": ["mfa"]
    },
    "sessionControls": {
        "signInFrequency": {
            "value": 24,
            "type": "hours",
            "authenticationType": "primaryAndSecondaryAuthentication",
            "frequencyInterval": "timeBased",
            "isEnabled": True
        },
        "persistentBrowser": {
            "mode": "never",   # don't persist browser session (require login on new browser)
            "isEnabled": True
        }
    }
}

resp = requests.post(
    "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies",
    headers=headers,
    json=ca_signin_freq
)
print(f"Sign-in frequency policy: {resp.status_code} {resp.json().get('id')}")

# Approach 2: Continuous Access Evaluation (CAE)
# CAE means Entra ID can revoke tokens in near-real-time if:
#   - User account is disabled
#   - Password is changed
#   - Suspicious sign-in detected
#   - Network location changes (for CAE-enabled apps)
# CAE is enabled by default for Exchange Online and SharePoint Online.
# No additional configuration required — it's automatic.
